import { News_and_events_View } from "../view/view.js";
import { News_and_events_model } from "../model/model.js";

export class News_and_events_Controller {
  constructor() {
    this.view = new News_and_events_View();
    this.model = new News_and_events_model();

    this.view.initial_render_for_news_and_events();

    this.render_news_and_events_plus_categories();
  }

  render_news_and_events_plus_categories = () => {
    this.model.registerListener((state) => {
      this.view.render_news_and_events(state);
    });
    this.model.fetch_news_and_events().then((res) => {
      if (res.success) {
        this.view.add_event_listeners(this.filter_categories);
      }
    });
  };

  filter_categories = (category_name, choose_state) => {
    this.model.filter_news_and_events_categories(category_name, choose_state);
  };
}
