export class News_and_events_View {
  constructor() {
    this.main_section = document.getElementById(
      "news_and_events_main_section1_section1",
    );
    this.news_section = document.getElementById("section_news");
    this.events_section = document.getElementById("section_events");
    this.news_cats = {
      categories: [],
      loaded: false,
    };
    this.events_cats = {
      categories: [],
      loaded: false,
    };
  }

  initial_render_for_news_and_events = () => {
    // caching page elements
    const news_btn = document.getElementById(
      "news_and_events_main_section1-section1-btn-news",
    );
    const events_btn = document.getElementById(
      "news_and_events_main_section1-section1-btn-events",
    );

    const news_nav_bar = document.getElementById(
      "news_and_events_main_section1_nav1_ul_news",
    );
    const events_nav_bar = document.getElementById(
      "news_and_events_main_section1_nav1_ul_events",
    );

    // removing elements on initial render
    events_nav_bar.style.display = "none";
    this.news_section.style.display = "none";
    this.events_section.style.display = "none";
    news_nav_bar.style.display = "flex";

    news_btn.addEventListener("click", () => {
      events_nav_bar.style.display = "none";
      news_nav_bar.style.display = "flex";
      events_btn.classList.remove(
        "news_and_events_main_section1-section1-btn_selected",
      );
      news_btn.classList.add(
        "news_and_events_main_section1-section1-btn_selected",
      );
      this.events_section.style.display = "none";
      this.news_section.style.display = "flex";
    });

    events_btn.addEventListener("click", () => {
      events_nav_bar.style.display = "flex";
      news_nav_bar.style.display = "none";
      events_btn.classList.add(
        "news_and_events_main_section1-section1-btn_selected",
      );
      news_btn.classList.remove(
        "news_and_events_main_section1-section1-btn_selected",
      );
      this.news_section.style.display = "none";
      this.events_section.style.display = "flex";
    });
  };

  render_news_and_events = (state) => {
    if (state.tables_loading) {
      // removing news and events section just in case
      this.news_section.style.display = "none";
      this.events_section.style.display = "none";

      // creating loading divs for section
      const section_loading_div = document.createElement("div");
      const loading_div = document.createElement("div");
      section_loading_div.setAttribute(
        "id",
        "news_and_events_main_section1_section1_div1_loading",
      );
      loading_div.classList.add("loading");

      // appending loading div
      section_loading_div.appendChild(loading_div);
      this.main_section.appendChild(section_loading_div);
    } else {
      const render_articles = (section) => {
        const loading = document.getElementById(
          "news_and_events_main_section1_section1_div1_loading",
        );

        if (loading) {
          this.main_section.removeChild(loading);
        }

        if (section === "news") {
          this.news_section.style.display = "none";
          this.news_section.replaceChildren();

          state.news.news_table.forEach((newsItem) => {
            // creating elements
            const article = document.createElement("article");
            const div1 = document.createElement("div");
            const div2 = document.createElement("div");
            const h4 = document.createElement("h4");
            const h3 = document.createElement("h3");
            const div3 = document.createElement("div");
            const h5 = document.createElement("h5");
            const div4 = document.createElement("div");
            const p2 = document.createElement("p");

            // declare variables here so they're visible everywhere
            let img, p1;

            if (newsItem.news_image) {
              img = document.createElement("img");
            } else {
              p1 = document.createElement("p");
            }

            // adding attributes to elements
            article.classList.add("section_news_article");
            div1.classList.add("section_news_article_div1");
            div2.classList.add("section_news_article_div2");
            h4.classList.add("section_news_div1_h4");
            h3.classList.add("section_news_div1_h3");
            div3.classList.add("section_news_article_div2_div1");

            if (newsItem.news_image) {
              img.classList.add("section_news_article_div2_div1_img");
              img.src = newsItem.news_image;
              img.alt = `${newsItem.news_headline.toLowerCase()} image`;
            } else {
              p1.classList.add("section_news_article_div2_div1_p");
            }

            h5.classList.add("section_news_article_div2_div1_h5");
            div4.classList.add("section_news_article_div2_div2");
            p2.classList.add("section_news_article_div2_div2_p");

            // adding text content to elements
            h4.textContent = `Date Published: ${newsItem.news_date}`;
            h3.textContent = `News Title: ${newsItem.news_headline}`;
            if (!newsItem.news_image)
              p1.textContent = "No Image for this News Article";
            h5.textContent = `News Category: ${newsItem.news_category}`;
            p2.textContent = newsItem.news_article;

            // appending elements
            this.news_section.appendChild(article);
            article.append(div1, div2);
            div1.append(h4, h3);
            div2.append(div3, div4);

            if (newsItem.news_image) {
              div3.append(img, h5);
            } else {
              div3.append(p1, h5);
            }

            div4.appendChild(p2);
          });

          this.news_section.style.display = "flex";
        } else if (section === "events") {
          this.events_section.replaceChildren();
          this.events_section.style.display = "none";

          state.events.events_table.forEach((eventItem) => {
            // creating elements
            const article = document.createElement("article");
            const div1 = document.createElement("div");
            const div2 = document.createElement("div");
            const h4_1 = document.createElement("h4");
            const h3_1 = document.createElement("h3");
            const div3 = document.createElement("div");
            const h4_2 = document.createElement("h4");
            const div4 = document.createElement("div");
            const span = document.createElement("span");
            const h3_2 = document.createElement("h3");
            const p = document.createElement("p");
            const div5 = document.createElement("div");
            const span_2 = document.createElement("span");
            const p2 = document.createElement("p");

            // adding attributes to elements
            article.classList.add("section_events_article");
            div1.classList.add("section_events_article_div1");
            h4_1.classList.add("section_events_div1_h4");
            h3_1.classList.add("section_events_div1_h3");
            div2.classList.add("section_events_article_div2");
            div3.classList.add("section_events_article_div2_div1");
            h4_2.classList.add("section_events_article_div2_div1_h4");
            div4.classList.add("section_events_article_div2_div1_div1");
            span.classList.add("section_events_article_div2_div1_div1_span");
            h3_2.classList.add("section_events_article_div2_div1_div1_h3");
            p.classList.add("section_events_article_div2_div1_p");
            div5.classList.add("section_events_article_div2_div2");
            span_2.classList.add("section_events_article_div2_div1_span");
            p2.classList.add("section_events_article_div2_div1_span_p");

            // adding text contect to elements
            h4_1.textContent = `Event Date: ${eventItem.event_date}`;
            h3_1.textContent = `Event Title: ${eventItem.event_headline}`;
            h4_2.textContent = `Event Time: ${eventItem.event_time}`;
            span.textContent = `Event Address:`;
            h3_2.textContent = eventItem.event_address;
            p.textContent = `Event Category: ${eventItem.event_type}`;
            span_2.textContent = `Event Description:`;
            p2.textContent = eventItem.event_description;

            // appending elements
            this.events_section.appendChild(article);
            article.append(div1, div2);
            div1.append(h4_1, h3_1);
            div2.append(div3, div5);
            div3.append(h4_2, div4, p);
            div4.append(span, h3_2);
            div5.append(span_2, p2);
          });
        }
      };

      const render_no_articles = (section) => {
        const loading = document.getElementById(
          "news_and_events_main_section1_section1_div1_loading",
        );

        if (loading) {
          this.main_section.removeChild(loading);
        }

        if (section === "news") {
          this.news_section.style.display = "none";

          this.news_section.replaceChildren();

          const div = document.createElement("div");
          const h3 = document.createElement("h3");
          div.id = "news_and_events_main_section1_section1_div1_no_news";
          h3.id = "news_and_events_main_section1_section1_div1_no_news_h3";
          h3.textContent = "Currently No News to Display";

          div.appendChild(h3);
          this.news_section.appendChild(div);

          this.news_section.style.display = "flex";
        } else if (section === "events") {
          this.events_section.style.display = "none";

          this.events_section.replaceChildren();

          const div = document.createElement("div");
          const h3 = document.createElement("h3");
          div.id = "news_and_events_main_section1_section1_div1_no_events";
          h3.id = "news_and_events_main_section1_section1_div1_no_events_h3";
          h3.textContent = "Currently No Events to Display";

          div.appendChild(h3);
          this.events_section.appendChild(div);
        }
      };

      const render_categories = () => {
        if (state.categories_loading) {
          const ul = Array.from(
            document.getElementsByClassName(
              "news_and_events_main_section1_nav1_ul_li_ul",
            ),
          );

          ul.forEach((ul_element) => {
            if (ul_element.id === "news_section_ul_category") {
              const li = document.createElement("li");
              const div = document.createElement("div");

              li.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li",
              );
              div.classList.add(
                "loading",
                "news_and_events_main_section1_nav1_ul_li_ul_li_loading",
              );

              ul_element.appendChild(li);
              li.appendChild(div);

              this.news_cats.loaded = false;
            } else if (ul_element.id === "events_section_ul_category") {
              const li = document.createElement("li");
              const div = document.createElement("div");

              li.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li",
              );
              div.classList.add(
                "loading",
                "news_and_events_main_section1_nav1_ul_li_ul_li_loading",
              );

              ul_element.appendChild(li);
              li.appendChild(div);

              this.events_cats.loaded = false;
            }
          });
        } else {
          if (!this.news_cats.loaded && !this.events_cats.loaded) {
            const ul_news = document.getElementById("news_section_ul_category");
            ul_news.replaceChildren();

            const ul_events = document.getElementById(
              "events_section_ul_category",
            );
            ul_events.replaceChildren();

            state.news.news_categories.forEach((cat) => {
              const li = document.createElement("li");
              const p = document.createElement("p");

              li.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li",
              );
              li.setAttribute("name", cat);
              p.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li_p",
              );
              p.textContent = cat;

              ul_news.appendChild(li);
              li.appendChild(p);

              this.news_cats.categories.push(li);
            });

            state.events.events_categories.forEach((cat) => {
              const li = document.createElement("li");
              const p = document.createElement("p");

              li.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li",
              );
              li.setAttribute("name", cat);
              p.classList.add(
                "news_and_events_main_section1_nav1_ul_li_ul_li_p",
              );
              p.textContent = cat;

              ul_events.appendChild(li);
              li.appendChild(p);

              this.events_cats.categories.push(li);
            });

            this.news_cats.loaded = true;
            this.events_cats.loaded = true;
          }
        }
      };

      if (
        state.news.news_table.length > 0 &&
        state.events.events_table.length > 0
      ) {
        render_articles("events");
        render_articles("news");
        render_categories();
      } else if (state.news.news_table.length > 0) {
        render_articles("news");
        render_no_articles("events");
        render_categories();
      } else if (state.events.events_table.length > 0) {
        render_articles("events");
        render_no_articles("news");
        render_categories();
      } else {
        render_no_articles("news");
        render_no_articles("events");
        render_categories();
      }
    }
  };

  add_event_listeners = (modelFunction) => {
    // cache ul and li elements
    // add mouse enter and mouse leave to relevant elements
    // add event listeners and model function to releveant categories

    const date_li = Array.from(
      document.getElementsByClassName(
        "news_and_events_main_section1_nav1_ul_li_date",
      ),
    );
    const category_li = Array.from(
      document.getElementsByClassName(
        "news_and_events_main_section1_nav1_ul_li_category",
      ),
    );

    date_li.forEach((li) => {
      if (li.id === "news_and_events_main_section1_nav1_ul_li_date_news") {
        const ul = document.getElementById("news_section_ul_date");

        li.addEventListener("mouseenter", () => {
          ul.style.display = "flex";
        });

        li.addEventListener("mouseleave", () => {
          ul.style.display = "none";
        });

        Array.from(ul.children).forEach((cat) => {
          cat.addEventListener("click", () => {
            if (cat.getAttribute("name") === "Latest News") {
              modelFunction(cat.getAttribute("name"), "News");
              ul.style.display = "none";
            } else if (cat.getAttribute("name") === "Oldest News") {
              modelFunction(cat.getAttribute("name"), "News");
              ul.style.display = "none";
            }
          });
        });
      } else if (
        li.id === "news_and_events_main_section1_nav1_ul_li_date_events"
      ) {
        const ul = document.getElementById("events_section_ul_date");

        li.addEventListener("mouseenter", () => {
          ul.style.display = "flex";
        });

        li.addEventListener("mouseleave", () => {
          ul.style.display = "none";
        });

        Array.from(ul.children).forEach((cat) => {
          cat.addEventListener("click", () => {
            if (cat.getAttribute("name") === "Latest Events") {
              modelFunction(cat.getAttribute("name"), "Events");
              ul.style.display = "none";
            } else if (cat.getAttribute("name") === "Oldest Events") {
              modelFunction(cat.getAttribute("name"), "Events");
              ul.style.display = "none";
            }
          });
        });
      }
    });

    category_li.forEach((li) => {
      if (li.id === "news_and_events_main_section1_nav1_ul_li_category_news") {
        const ul1 = document.getElementById("news_section_ul_category");

        li.addEventListener("mouseenter", () => {
          ul1.style.display = "flex";
        });

        li.addEventListener("mouseleave", () => {
          ul1.style.display = "none";
        });

        this.news_cats.categories.forEach((cat) => {
          cat.addEventListener("click", () => {
            modelFunction(cat.getAttribute("name"), "News");
            ul1.style.display = "none";
          });
        });
      } else if (
        li.id === "news_and_events_main_section1_nav1_ul_li_category_events"
      ) {
        const ul2 = document.getElementById("events_section_ul_category");

        li.addEventListener("mouseenter", () => {
          ul2.style.display = "flex";
        });

        li.addEventListener("mouseleave", () => {
          ul2.style.display = "none";
        });

        this.events_cats.categories.forEach((cat) => {
          cat.addEventListener("click", () => {
            modelFunction(cat.getAttribute("name"), "Events");
            ul2.style.display = "none";
          });
        });
      }
    });
  };
}
