export class News_and_events_model {
  constructor() {
    this.state = {
      news: {
        news_table: [],
        news_categories: [],
      },
      events: {
        events_table: [],
        events_categories: [],
      },
      tables_loading: false,
      categories_loading: false,
    };

    this.listeners = [];
  }

  setState = (newState) => {
    this.state = { ...this.state, ...newState };

    this.notifyListeners();

    console.log(this.state);

    return this.state;
  };

  getState = (stateName) => {
    if (this.state[stateName]) {
      return this.state[stateName];
    } else {
      console.log("no state exists");
    }
  };

  registerListener = (listener) => {
    this.listeners.push(listener);

    listener(this.state);
  };

  notifyListeners = () => {
    this.listeners.forEach((listener) => {
      listener(this.state);
    });
  };

  fetch_news_and_events = () => {
    // change state
    this.setState({
      tables_loading: true,
      categories_loading: true,
    });

    if (process.env.NODE_ENV === "production") {
      return fetch(
        "https://abbeyroad.org.uk/api/news&events_page/fetch_news&events",
      )
        .then((res) => {
          return res.json();
        })
        .then((res) => {
          console.log(res);
          if (res.success && res.tables) {
            this.setState({
              news: {
                news_table: res.tables.news_table,
                news_categories: [],
              },
              events: {
                events_table: [],
                events_categories: res.tables.events_table,
              },
              tables_loading: false,
            });

            return this.fetch_news_and_event_categories()
              .then((res) => {
                if (res.success) {
                  return Promise.resolve(res);
                } else {
                  return Promise.reject(false);
                }
              })
              .catch((err) => {
                console.log(err);
                return Promise.reject(false);
              });
          } else {
            console.log("error");
            this.setState({
              news: {
                news_table: [],
                news_categories: [],
              },
              events: {
                events_table: [],
                events_categories: [],
              },
              tables_loading: false,
            });
            return this.fetch_news_and_event_categories()
              .then((res) => {
                console.log(res);
                if (res.success) {
                  return Promise.resolve(res);
                } else {
                  return Promise.reject(false);
                }
              })
              .catch((err) => {
                console.log(err);
                return Promise.reject(false);
              });
          }
        })
        .catch((err) => {
          console.log(err);
          this.setState({
            news: {
              news_table: res.tables.news_table,
              news_categories: [],
            },
            events: {
              events_table: [],
              events_categories: res.tables.events_table,
            },
            tables_loading: false,
          });
          return Promise.resolve(false);
        });
    } else {
      return fetch(
        "http://localhost:3001/api/news&events_page/fetch_news&events",
      )
        .then((res) => {
          return res.json();
        })
        .then((res) => {
          if (res.success && res.tables) {
            this.setState({
              news: {
                news_table: res.tables.news_table,
                news_categories: [],
              },
              events: {
                events_table: res.tables.events_table,
                events_categories: [],
              },
              tables_loading: false,
            });

            return this.fetch_news_and_event_categories()
              .then((res) => {
                if (res.success) {
                  return Promise.resolve(res);
                } else {
                  return Promise.reject(false);
                }
              })
              .catch((err) => {
                console.log(err);
                return Promise.reject(false);
              });
          } else {
            console.log("error");
            this.setState({
              news: {
                news_table: [],
                news_categories: [],
              },
              events: {
                events_table: [],
                events_categories: [],
              },
              tables_loading: false,
            });
            return this.fetch_news_and_event_categories()
              .then((res) => {
                console.log(res);
                if (res.success) {
                  return Promise.resolve(res);
                } else {
                  return Promise.reject(false);
                }
              })
              .catch((err) => {
                console.log(err);
                return Promise.reject(false);
              });
          }
        })
        .catch((err) => {
          console.log(err);
          this.setState({
            news: {
              news_table: res.tables.news_table,
              news_categories: [],
            },
            events: {
              events_table: [],
              events_categories: res.tables.events_table,
            },
            tables_loading: false,
          });
          return Promise.resolve(false);
        });
    }
  };

  fetch_news_and_event_categories = () => {
    // if there events in array
    if (
      this.state.news.news_table.length > 0 &&
      this.state.events.events_table.length > 0
    ) {
      // adding default properties to event_categories variable
      let news_categories = ["Updates", "Community", "Services"];

      let event_categories = ["Meetings", "Fundrasing", "Community Outings"];

      // caching event_categories array = [];
      let new_news_categories = [];
      let new_event_categories = [];

      // loop through events array and cache unique event_type property into
      // new_event_categories
      this.state.news.news_table.forEach((news) => {
        // formatting event_type string to be capitalized
        let news_name_trim = news.news_category.trim();
        let news_name_capitalized =
          news_name_trim.charAt(0).toUpperCase() +
          news_name_trim.slice(1).toLowerCase();

        if (!new_news_categories.includes(news_name_capitalized)) {
          new_news_categories.push(news_name_capitalized);
        }
      });
      this.state.events.events_table.forEach((event) => {
        // formatting event_type string to be capitalized
        let event_name_trim = event.event_type.trim();
        let event_name_capitalized =
          event_name_trim.charAt(0).toUpperCase() +
          event_name_trim.slice(1).toLowerCase();

        if (!new_event_categories.includes(event_name_capitalized)) {
          new_event_categories.push(event_name_capitalized);
        }
      });

      // loop through unique new_event_categories variable and add unique values
      // to default event_categories if the value doesnt already exist
      new_event_categories.forEach((event_name) => {
        if (!event_categories.includes(event_name)) {
          event_categories.push(event_name);
        }
      });
      new_news_categories.forEach((news_name) => {
        if (!news_categories.includes(news_name)) {
          news_categories.push(news_name);
        }
      });

      // set new event_categories state and turn off loading
      this.setState({
        news: {
          news_categories: news_categories,
          news_table: this.state.news.news_table,
        },
        events: {
          events_categories: event_categories,
          events_table: this.state.events.events_table,
        },
        tables_loading: false,
        categories_loading: false,
      });

      return Promise.resolve({
        success: true,
      });
    }

    // if there are no events in array
    else {
      if (this.state.news.news_table.length > 0) {
        // adding default properties to event_categories variable
        let news_categories = ["Updates", "Community", "Services"];

        let event_categories = ["Meetings", "Fundrasing", "Community Outings"];

        let new_news_categories = [];

        this.state.news.news_table.forEach((news) => {
          // formatting event_type string to be capitalized
          let news_name_trim = news.news_category.trim();
          let news_name_capitalized =
            news_name_trim.charAt(0).toUpperCase() +
            news_name_trim.slice(1).toLowerCase();

          if (!new_news_categories.includes(news_name_capitalized)) {
            new_news_categories.push(news_name_capitalized);
          }
        });

        new_news_categories.forEach((news_name) => {
          if (!news_categories.includes(news_name)) {
            news_categories.push(news_name);
          }
        });

        this.setState({
          news: {
            news_categories: news_categories,
            news_table: this.state.news.news_table,
          },
          events: {
            events_categories: event_categories,
            events_table: this.state.events.events_table,
          },
          tables_loading: false,
          categories_loading: false,
        });

        return Promise.resolve({
          success: true,
        });
      } else if (this.state.events.events_table.length > 0) {
        // adding default properties to event_categories variable
        let news_categories = ["Updates", "Community", "Services"];

        let event_categories = ["Meetings", "Fundrasing", "Community Outings"];

        let new_event_categories = [];

        this.state.events.events_table.forEach((event) => {
          // formatting event_type string to be capitalized
          let event_name_trim = event.event_type.trim();
          let event_name_capitalized =
            event_name_trim.charAt(0).toUpperCase() +
            event_name_trim.slice(1).toLowerCase();

          if (!new_event_categories.includes(event_name_capitalized)) {
            new_event_categories.push(event_name_capitalized);
          }
        });

        new_event_categories.forEach((event_name) => {
          if (!event_categories.includes(event_name)) {
            event_categories.push(event_name);
          }
        });

        this.setState({
          news: {
            news_categories: news_categories,
            news_table: this.state.news.news_table,
          },
          events: {
            events_categories: event_categories,
            events_table: this.state.events.events_table,
          },
          tables_loading: false,
          categories_loading: false,
        });

        return Promise.resolve({
          success: true,
        });
      } else {
        this.setState({
          news: {
            news_categories: ["Updates", "Community", "Services"],
            news_table: this.state.news.news_table,
          },
          events: {
            events_categories: ["Meetings", "Fundrasing", "Community Outings"],
            events_table: this.state.events.events_table,
          },
          tables_loading: false,
          categories_loading: false,
        });

        return Promise.resolve({
          success: true,
        });
      }
    }
  };

  filter_news_and_events_categories = (category_name, choose_state) => {
    if (category_name === "Latest News" && choose_state === "News") {
      const latestNews = [...this.state.news.news_table].sort((a, b) => {
        const today = new Date();

        // convert 'dd-mm-yyyy' → Date
        const [dayA, monthA, yearA] = a.news_date.split("-").map(Number);
        const [dayB, monthB, yearB] = b.news_date.split("-").map(Number);

        const dateA = new Date(yearA, monthA - 1, dayA);
        const dateB = new Date(yearB, monthB - 1, dayB);

        // absolute difference from today
        const diffA = Math.abs(dateA - today);
        const diffB = Math.abs(dateB - today);

        return diffA - diffB; // closer dates come first
      });

      this.setState({
        news: {
          news_table: latestNews,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: this.state.events.events_table,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    } else if (category_name === "Latest Events" && choose_state === "Events") {
      const latestEvents = [...this.state.events.events_table].sort((a, b) => {
        const today = new Date();

        // convert 'dd-mm-yyyy' → Date
        const [dayA, monthA, yearA] = a.event_date.split("-").map(Number);
        const [dayB, monthB, yearB] = b.event_date.split("-").map(Number);

        const dateA = new Date(yearA, monthA - 1, dayA);
        const dateB = new Date(yearB, monthB - 1, dayB);

        // absolute difference from today
        const diffA = Math.abs(dateA - today);
        const diffB = Math.abs(dateB - today);

        return diffB - diffA; // closer dates come first
      });

      this.setState({
        news: {
          news_table: this.state.news.news_table,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: latestEvents,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    } else if (category_name === "Oldest News" && choose_state === "News") {
      const oldestNews = [...this.state.news.news_table].sort((a, b) => {
        const today = new Date();

        // convert 'dd-mm-yyyy' → Date
        const [dayA, monthA, yearA] = a.news_date.split("-").map(Number);
        const [dayB, monthB, yearB] = b.news_date.split("-").map(Number);

        const dateA = new Date(yearA, monthA - 1, dayA);
        const dateB = new Date(yearB, monthB - 1, dayB);

        // absolute difference from today
        const diffA = Math.abs(dateA - today);
        const diffB = Math.abs(dateB - today);

        return diffB - diffA; // closer dates come first
      });

      this.setState({
        news: {
          news_table: oldestNews,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: this.state.events.events_table,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    } else if (category_name === "Oldest Events" && choose_state === "Events") {
      const oldestEvents = [...this.state.events.events_table].sort((a, b) => {
        const today = new Date();

        // convert 'dd-mm-yyyy' → Date
        const [dayA, monthA, yearA] = a.event_date.split("-").map(Number);
        const [dayB, monthB, yearB] = b.event_date.split("-").map(Number);

        const dateA = new Date(yearA, monthA - 1, dayA);
        const dateB = new Date(yearB, monthB - 1, dayB);

        // absolute difference from today
        const diffA = Math.abs(dateA - today);
        const diffB = Math.abs(dateB - today);

        return diffA - diffB; // closer dates come first
      });

      this.setState({
        news: {
          news_table: this.state.news.news_table,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: oldestEvents,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    } else if (category_name && choose_state === "News") {
      const news_today = new Date(); // not strictly needed, but kept for context

      const news_newFilteredArray = [...this.state.news.news_table].sort(
        (a, b) => {
          // 1️⃣ Bring primaryType to the top
          if (
            a.news_category === category_name &&
            b.news_category !== category_name
          )
            return -1;
          if (
            b.news_category === category_name &&
            a.news_category !== category_name
          )
            return 1;

          // 2️⃣ If same type (or neither is primaryType), sort by latest date
          const [dayA, monthA, yearA] = a.news_date.split("-").map(Number);
          const [dayB, monthB, yearB] = b.news_date.split("-").map(Number);

          const dateA = new Date(yearA, monthA - 1, dayA);
          const dateB = new Date(yearB, monthB - 1, dayB);

          return dateB - dateA; // latest dates first
        },
      );

      this.setState({
        news: {
          news_table: news_newFilteredArray,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: this.state.events.events_table,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    } else if (category_name && choose_state === "Events") {
      const events_today = new Date(); // not strictly needed, but kept for context

      const events_newFilteredArray = [...this.state.events.events_table].sort(
        (a, b) => {
          // 1️⃣ Bring primaryType to the top
          if (a.event_type === category_name && b.event_type !== category_name)
            return -1;
          if (b.event_type === category_name && a.event_type !== category_name)
            return 1;

          // 2️⃣ If same type (or neither is primaryType), sort by latest date
          const [dayA, monthA, yearA] = a.event_date.split("-").map(Number);
          const [dayB, monthB, yearB] = b.event_date.split("-").map(Number);

          const dateA = new Date(yearA, monthA - 1, dayA);
          const dateB = new Date(yearB, monthB - 1, dayB);

          return dateB - dateA; // latest dates first
        },
      );

      this.setState({
        news: {
          news_table: this.state.news.news_table,
          news_categories: this.state.news.news_categories,
        },
        events: {
          events_table: events_newFilteredArray,
          events_categories: this.state.events.events_categories,
        },
        tables_loading: this.state.tables_loading,
        categories_loading: this.state.categories_loading,
      });
    }
  };
}
